import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"25. Redundancy And Related Entitlements","description":"","frontmatter":{"title":"25. Redundancy And Related Entitlements","eba":"Allied Health Professionals 2021-2026","topics":["leave","wages","employment","redundancy"]},"headers":[],"relativePath":"ebas/allied-health/employment/25-redundancy-and-related-entitlements.md","filePath":"ebas/allied-health/employment/25-redundancy-and-related-entitlements.md"}'),r={name:"ebas/allied-health/employment/25-redundancy-and-related-entitlements.md"};function i(s,e,l,p,d,c){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_25-redundancy-and-related-entitlements" tabindex="-1">25. Redundancy And Related Entitlements <a class="header-anchor" href="#_25-redundancy-and-related-entitlements" aria-label="Permalink to &quot;25. Redundancy And Related Entitlements&quot;">​</a></h1><p><strong>25.1</strong> Arrangement This clause is arranged as follows:</p><p><strong>(a)</strong> Arrangement (subclause 25.1);</p><p><strong>(b)</strong> Definitions (subclause 25.2);</p><p><strong>(c)</strong> Redeployment (subclause 25.3);</p><p><strong>(d)</strong> Support to Affected Employees (subclause 25.4);</p><p><strong>(e)</strong> Salary Maintenance (subclause 25.5);</p><p><strong>(f)</strong> Preservation of accrued leave (subclause 25.6);</p><p><strong>(g)</strong> Relocation (subclause 25.7);</p><p><strong>(h)</strong> Employment terminates due to Redundancy (subclause 25.8); and</p><p><strong>(i)</strong> Exception to application of Victorian Government’s policy with respect to severance pay (subclause 25.9).</p><p><strong>25.2</strong> Definitions</p><p><strong>(a)</strong> Affected Employee for this clause 25 means an Employee whose role will be redundant.</p><p><strong>(b)</strong> Comparable Role means an on-going role that:</p><p><strong>(i)</strong> is the same profession as that of the Affected Employee’s redundant position or if not, is in a profession acceptable to the Affected Employee;</p><p><strong>(ii)</strong> is any of the following: A. in the same clinical specialty as that of the Affected Employee’s former position; B. in a clinical specialty acceptable to the Affected Employee; or C. a position that with the reasonable support described at 25.3(g), the Affected Employee could undertake;</p><p><strong>(iii)</strong> is the same grade/level/class as the Affected Employee’s redundant position or is a different grade/level/class acceptable to the Affected Employee;</p><p><strong>(iv)</strong> takes into account the number of ordinary hours normally worked by the Affected Employee or is a different number of ordinary hours acceptable to the Affected Employee;</p><p><strong>(v)</strong> is a Reasonable Distance from the Affected Employee’s current work location or is a distance that is not reasonable but is acceptable to the Affected Employee;</p><p><strong>(vi)</strong> takes the Affected Employee’s personal circumstances, including family responsibilities, into account; and</p><p><strong>(vii)</strong> takes account of health and safety considerations.</p><p><strong>(c)</strong> Consultation is as defined at subclause 13.2(a) (Consultation) of this Agreement.</p><p><strong>(d)</strong> Continuity of Service means that the service of the Affected Employee is treated as unbroken. However, continuity of service is not broken where an Employer pays out accrued annual leave or long service leave upon termination in accordance with this Agreement.</p><p><strong>(e)</strong> Reasonable Distance means a distance that has regard to the Affected Employee’s original work location, current home address, capacity of the Affected Employee to travel, additional travelling time, effects of the personal circumstances of the Affected Employee, including family commitments and responsibilities and other matters raised by the Affected Employee, or assistance provided by their Employer.</p><p><strong>(f)</strong> Redeployment Period means a period of 13 weeks from the time the Employer notifies the Affected Employee in writing that Consultation under <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> is complete and that the Redeployment Period has begun.</p><p><strong>(g)</strong> Redundancy means the Employer no longer requires the Affected Employee’s job to be performed by anyone because of changes in the operational requirements of the Employer’s enterprise.</p><p><strong>(h)</strong> Relocation means an Affected Employee is required to move to a different campus as a result of an organisational change on either a temporary or permanent basis.</p><p><strong>(i)</strong> Salary Maintenance means an amount representing the difference between what the Affected Employee was normally paid prior to the Affected Employee’s role being made redundant and the amount paid in the Affected Employee’s new role following redeployment.</p><p><strong>25.3</strong> Redeployment An Affected Employee whose role will be redundant will be considered for redeployment during the Redeployment Period.</p><p><strong>(a)</strong> Employee to be advised in writing The Affected Employee must be advised in writing of:</p><p><strong>(i)</strong> the date the Affected Employee’s role is to be redundant;</p><p><strong>(ii)</strong> details of the redeployment process;</p><p><strong>(iii)</strong> the reasonable support that will be provided in accordance with subclause 25.3(g); and</p><p><strong>(iv)</strong> the Affected Employee’s rights and obligations.</p><p><strong>(b)</strong> Employer obligations The Employer will:</p><p><strong>(i)</strong> make every effort to redeploy the Affected Employee to a Comparable Role in terms of grade/level/class and income, including giving preference to an Affected Employee/s for any vacant Comparable Roles and appointing a case manager to provide the Affected Employee with support and assistance;</p><p><strong>(ii)</strong> take into account the personal circumstances of the Affected Employee, including family commitments and responsibilities; and</p><p><strong>(iii)</strong> where the Employer is creating a new role/s substantially similar to the Affected Employee’s redundant role, give priority to the redeployment of an Affected Employee/s to the new position/s and only consider other applicants that are not Affected Employees if the Affected Employee’s do not fill the new role/s.</p><p>Example Due to a change in services offered, the Employer is reducing the number of Physiotherapists it employs from 10 to five (5). In a ‘spill and fill’, the Employer will consider the Affected Employees for the new roles and will only consider other applicants if the Affected Employees do not fill the five (5) vacant positions.</p><p><strong>(c)</strong> Employee obligations The Affected Employee must actively participate in the redeployment process including:</p><p><strong>(i)</strong> identifying appropriate retraining needs;</p><p><strong>(ii)</strong> developing a resume/CV to assist in securing redeployment; and</p><p><strong>(iii)</strong> actively monitoring and exploring appropriate redeployment opportunities and working with the appointed case manager.</p><p><strong>(d)</strong> Rejecting a Comparable Role Where an Affected Employee rejects an offer of redeployment to a Comparable Role (as defined in this clause 25), the Affected Employee may be ineligible for a departure package referred to at subclause 25.8.</p><p><strong>(e)</strong> Rejecting a non-Comparable Role For the avoidance of doubt, where an Affected Employee rejects an offer of redeployment to a role that is not a Comparable Role (as defined in this clause 25), the Affected Employee will be eligible for a departure package referred to at subclause 25.8.</p><p><strong>(f)</strong> Temporary alternative duties</p><p>An Affected Employee awaiting redeployment may be transferred to temporary alternative duties within the same campus or, where part of the Affected Employee’s existing employment conditions (or by agreement), at another campus. Such temporary duties will be in accordance with the Affected Employee’s skills, experience, clinical area and profession.</p><p><strong>(g)</strong> Support for redeployment For an available role to be considered a Comparable Role, the Employer must provide the reasonable support necessary for the Affected Employee to perform the role which may include:</p><p><strong>(i)</strong> theory training relevant to the clinical area or environment of the role into which the Affected Employee is to be redeployed;</p><p><strong>(ii)</strong> a defined period of up to 12 weeks in which the Affected Employee works in a supernumerary capacity;</p><p><strong>(iii)</strong> support from educational staff in the clinical environment; and</p><p><strong>(iv)</strong> a review at 12 weeks or earlier to determine what, if any, further training is required.</p><p><strong>(h)</strong> Where no redeployment available If at any time during the Redeployment Period it is agreed that it is unlikely that the Affected Employee will be successfully redeployed, the Affected Employee may accept a redundancy package. Where this occurs, the Affected Employee will be entitled to an additional payment of the lesser of 13 weeks or the remaining Redeployment Period.</p><p><strong>(i)</strong> Non-Comparable Role An Affected Employee may agree to be redeployed to a role that is not a Comparable Role.</p><p><strong>25.4</strong> Support to Affected Employees The Employer will provide Affected Employees whose position has been declared redundant with support and assistance which will include, where relevant:</p><p><strong>(a)</strong> counselling and support services;</p><p><strong>(b)</strong> retraining;</p><p><strong>(c)</strong> preparation of job applications;</p><p><strong>(d)</strong> interview coaching;</p><p><strong>(e)</strong> time off to attend job interviews; and</p><p><strong>(f)</strong> funding of independent financial advice for Affected Employees eligible to receive a separation package. Other assistance may include but is not limited to career planning or employment services.</p><p><strong>25.5</strong> Salary Maintenance</p><p><strong>(a)</strong> Entitlement to Salary Maintenance</p><p>An Affected Employee who is successfully redeployed will be entitled to Salary Maintenance where the Affected Employee’s pay is reduced because the new role:</p><p><strong>(i)</strong> is a lower grade/level/class;</p><p><strong>(ii)</strong> involves working fewer hours; and/or</p><p><strong>(iii)</strong> removes eligibility for penalties, loadings and the like.</p><p><strong>(b)</strong> Period of Salary Maintenance Salary Maintenance will be for a period of 52 weeks from the date the Affected Employee is redeployed except where the Affected Employee:</p><p><strong>(i)</strong> accepts another position within the Salary Maintenance period; and</p><p><strong>(ii)</strong> is paid in the other position an amount equal to or greater than the role that was made redundant.</p><p><strong>25.6</strong> Preservation of accrued leave An Affected Employee entitled to Salary Maintenance will have:</p><p><strong>(a)</strong> the long service leave and annual leave they have accrued prior to the redeployment preserved. Specifically, the value of the leave and the number of hours accrued immediately prior to redeployment will not be reduced as a result of redeployment; and</p><p><strong>(b)</strong> the number of hours of personal leave they have accrued prior to redeployment preserved.</p><p><strong>25.7</strong> Relocation</p><p><strong>(a)</strong> Employer to advise in writing of Relocation As soon as practicable but no less than seven (7) days after a decision is made by the Employer to temporarily or permanently relocate an Affected Employee, the Employer will advise the Affected Employee in writing of the decision, the proposed timing of the Relocation and any other alternatives available to the Affected Employee. In addition, the Employer will:</p><p><strong>(i)</strong> ensure the Relocation is a Reasonable Distance, unless otherwise agreed;</p><p><strong>(ii)</strong> ensure that the Affected Employee is provided with information on the new location’s amenities, layout and local operations prior to the Relocation; and</p><p><strong>(iii)</strong> consult with the Union or other nominated Employee representative regarding the content of such information.</p><p><strong>(b)</strong> Entitlement to relocation allowance An Affected Employee is entitled to a relocation allowance where permanent or temporary Relocation results in additional cost to the Affected Employee for travel and/or other expenses.</p><p><strong>(c)</strong> Employee to provide written estimate</p><p>The Affected Employee must make written application to the Employer with a written estimate of the additional travelling cost and other expenses for the period of redeployment up to a maximum of 12 months.</p><p><strong>(d)</strong> Payment</p><p><strong>(i)</strong> The Employer will pay the Affected Employee a relocation allowance of up to $1900.00 based on the written estimate of the Affected Employee referred to at subclause 25.7(c) where the Employer accepts the estimate represents the additional cost to the Affected Employee. The Employer will only refuse to accept the estimate represents the additional cost to the Affected Employee where the Employer has evidence that the estimate does not represent the additional cost to the Affected Employee. The allowance shall be paid as a lump sum.</p><p>Example 1 The Employee provides the Employer with a written estimate of the additional travelling cost and other expenses for the period of redeployment up to a maximum of 12 months of $3,000. The Employer does not have evidence that the estimate does not represent the additional cost to the Affected Employee. The Employer will pay a relocation allowance of $1,900 to the Employee as a lump sum. Example 2 The Employee provides the Employer with a written estimate of the additional travelling cost and other expenses for the period of redeployment up to a maximum of 12 months of $1,000. The Employer does not have evidence that the estimate does not represent the additional cost to the Affected Employee. The Employer will pay a relocation allowance of $1,000 to the Employee as a lump sum.</p><p><strong>(ii)</strong> When considering the Affected Employee’s estimate, the Employer may have regard to the Reasonable Distance.</p><p><strong>(iii)</strong> In the event of a dispute about the Affected Employee’s estimate it will be resolved under <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> (Dispute Resolution Procedure).</p><p><strong>(e)</strong> Exceptions An Affected Employee is not entitled to the relocation allowance if the site or campus to which the Affected Employee is being relocated to is a location to which they can be expected to be deployed as part of their existing employment conditions.</p><p><strong>(f)</strong> Fixed term Employees not excluded An Affected Employee on a fixed term contract who is relocated will be covered by the terms of this clause 25 for the duration of the fixed term contract.</p><p><strong>25.8</strong> Employment terminates due to Redundancy The Victorian Government’s policy with respect to public sector redundancy and the entitlements upon termination of employment as a result of Redundancy are</p><p>set out in the Public Sector Workplace Relations Policies 2015. The policy as at the time this Agreement comes into operation applies to Employees but does not form part of this Agreement.</p><p><strong>25.9</strong> Exception to application of Victorian Government’s policy with respect to severance pay Where the Affected Employee’s Employer secures for them a Comparable Role (as defined) with another Employer covered by this Agreement, which:</p><p><strong>(a)</strong> is within a Reasonable Distance of the work site of the redundant position;</p><p><strong>(b)</strong> provides Continuity of Service;</p><p><strong>(c)</strong> where the Comparable Role results in a loss of income, the salary maintenance at subclause 25.5 will be applied; and</p><p><strong>(d)</strong> where relevant, is consistent with the financial and other support provided to an internal redeployee; the Employee will be considered successfully redeployed as though the employment was with the same Employer and no severance pay will apply.</p><p>Plain language terms: agreement title.</p>',96)])])}const f=t(r,[["render",i]]);export{h as __pageData,f as default};
